export function getStory(slug: string): Story | undefined {
  return stories.find((s) => s.slug === slug);
}

export function getChapter(
  slug: string,
  chapterNum: number
): Chapter | undefined {
  const story = getStory(slug);
  return story?.chapters.find((c) => c.number === chapterNum);
}
